import { writeActiveStudioSession } from "../activeStudioSession.js";
import { createAgentSession } from "../agentSessionChannel.js";
import { openChromelessWindow } from "../browser.js";
import { NotAuthenticatedError } from "../errors.js";
import { isValidStudioRoute } from "../studioRoutes.js";
function ensureStudioPath(p) {
    if (!p.startsWith("/studio")) {
        return "/studio";
    }
    return p;
}
/**
 * Internal: creates a new Studio session, opens the browser, and writes
 * the active-session file. Does NOT start event polling. Called only by
 * openStudioTo. Do not call directly.
 */
export async function createStudioSession({ serviceUrl, apiKey, sessionId, initialPath = "/studio", clientHeaders, }) {
    if (!apiKey) {
        throw new NotAuthenticatedError();
    }
    initialPath = ensureStudioPath(initialPath);
    if (!isValidStudioRoute(initialPath)) {
        throw new Error(`Studio route not allowed: ${initialPath}`);
    }
    await createAgentSession({
        serviceUrl,
        apiKey,
        sessionId,
        extraHeaders: clientHeaders,
    });
    writeActiveStudioSession({ sessionId, serviceUrl });
    const separator = initialPath.includes("?") ? "&" : "?";
    const url = `${serviceUrl}${initialPath}${separator}session=${encodeURIComponent(sessionId)}`;
    openChromelessWindow(url);
    return { sessionId, serviceUrl };
}
